import UIKit

enum PDFGenerator {
    static func generatePDF(from pages: [UIImage]) -> Data? {
        guard !pages.isEmpty else { return nil }

        let pageSize = CGSize(width: 612, height: 792)
        let renderer = UIGraphicsPDFRenderer(bounds: CGRect(origin: .zero, size: pageSize))

        return renderer.pdfData { context in
            for page in pages {
                context.beginPage()
                let aspectRatio = page.size.width / page.size.height
                var drawRect = CGRect(origin: .zero, size: pageSize)
                if aspectRatio > pageSize.width / pageSize.height {
                    drawRect.size.height = pageSize.width / aspectRatio
                } else {
                    drawRect.size.width = pageSize.height * aspectRatio
                }
                drawRect.origin.x = (pageSize.width - drawRect.width) / 2
                drawRect.origin.y = (pageSize.height - drawRect.height) / 2
                page.draw(in: drawRect)
            }
        }
    }
}
